solution_code:
#include <cstddef>
#include <iostream>

int findMax(const int* arr, int length)
{
    int max{ arr[0] };
    for (int i{ 1 }; i < length; ++i)
    {
        if (arr[i] > max)
            max = arr[i];
    }
    return max;
}

int main()
{
    int arr[10]{};

    // sizeof works here because arr has not decayed yet
    const int length{ static_cast<int>(sizeof(arr) / sizeof(arr[0])) };

    for (int i{ 0 }; i < length; ++i)
        std::cin >> arr[i];

    std::cout << "max: " << findMax(arr, length) << '\n';

    return 0;
}
